#include <stdio.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    const char *days[] = {"Monday","Tuesday","Wednesday","Thursday","Friday","Saturday","Sunday"};
    while (T--) {
        int n;
        if (scanf("%d", &n) != 1) break;
        if (n >= 1 && n <= 7) {
            printf("%s\n", days[n-1]);
        } else {
            printf("Invalid input\n");
        }
    }
    return 0;
}

